class Solution {
    public boolean canMakeSubsequence(String str1, String str2) {
        int n = str1.length();
        int m = str2.length();

        // Preprocess next array
        int[][] next = new int[n + 1][26];
        for (int c = 0; c < 26; c++) {
            next[n][c] = -1;
        }

        for (int i = n - 1; i >= 0; i--) {
            for (int c = 0; c < 26; c++) {
                char current = str1.charAt(i);
                int currentInt = current - 'a';
                int cMinus1 = (c - 1 + 26) % 26;
                if (currentInt == c || currentInt == cMinus1) {
                    next[i][c] = i;
                } else {
                    next[i][c] = next[i + 1][c];
                }
            }
        }

        int i = 0;
        for (int j = 0; j < m; j++) {
            int c = str2.charAt(j) - 'a';
            int pos = next[i][c];
            if (pos == -1) {
                return false;
            }
            i = pos + 1;
            if (i > n) {
                return false;
            }
        }
        return true;
    }
}

